  private globalCount = 0;
  private readonly identifierCounts = new Map<string, number>();

  constructor(private readonly globalLimit: number) {}

  consume(key: string, identifierLimit: number): boolean {
    const identifierCount = this.identifierCounts.get(key) ?? 0;
    if (this.globalCount >= this.globalLimit || identifierCount >= identifierLimit) {
      return false;
    }
    this.globalCount += 1;
    this.identifierCounts.set(key, identifierCount + 1);
    return true;
  }
}

describe("independent-identifier campaign budget", () => {
  it("distinguishes campaign scope while preserving the inherited identifier boundary", () => {
    const identifiers = Array.from(
      { length: 12 },
      (_, index) => `synthetic-${index}@example.test`
    );
    const accounts = new Set(identifiers);
    const addresses = identifiers.map((_, index) =>
      index % 2 === 0
        ? `198.51.100.${index + 1}`
        : `203.0.113.${index + 1}`
    );

    const perIdentifierDeliveries: string[] = [];
    const perIdentifier = new PasswordResetService(
      accounts,
      (identifier) => perIdentifierDeliveries.push(identifier),
      () => 1_000
    );
    const perIdentifierResponses = identifiers.map((identifier, index) =>
      perIdentifier.request(identifier, addresses[index]!)
    );

    const hierarchicalDeliveries: string[] = [];
    const hierarchical = new PasswordResetService(
      accounts,
      (identifier) => hierarchicalDeliveries.push(identifier),
      () => 1_000,
      new HierarchicalCampaignBudget(5)
    );
    const hierarchicalResponses = identifiers.map((identifier, index) =>
      hierarchical.request(identifier, addresses[index]!)
    );

    expect(perIdentifierDeliveries).toHaveLength(12);
    expect(hierarchicalDeliveries).toHaveLength(5);
    expect(new Set([...perIdentifierResponses, ...hierarchicalResponses].map(JSON.stringify)).size)
      .toBe(1);

    const repeatedDeliveries: string[] = [];
    const repeatedIdentifier = new PasswordResetService(
      new Set([identifiers[0]!]),
      (identifier) => repeatedDeliveries.push(identifier),
      () => 1_000
    );
    for (let index = 0; index < 4; index += 1) {
      repeatedIdentifier.request(identifiers[0]!, `192.0.2.${index + 1}`);
    }
    expect(repeatedDeliveries).toHaveLength(3);
  });
});
